export function validateAndNormalizeAuthenticationCredentialsForOutgoingRequest(
  apiKey: string | null | undefined,
  authToken: string | null | undefined,
): { resolvedApiKey: string | null; resolvedAuthToken: string | null } {
  const resolvedApiKey = apiKey?.trim() ?? null;
  const resolvedAuthToken = authToken?.trim() ?? null;
  if (!resolvedApiKey && !resolvedAuthToken) {
    throw new AnthropicError(
      'Either apiKey or authToken must be provided to authenticate requests.',
    );
  }
  return { resolvedApiKey, resolvedAuthToken };
}
